    BE: { kanton: 'BE', erlassName: "Verordnung über die Notariatsgebühren (GebVN)", erlassNr: "BSG 169.81", artikel: "Art. 9 Abs. 1 i.V.m. Art. 1a Abs. 2, Art. 3a Abs. 1 GebVN (BSG 169.81)", stand: "01.03.2022", verifiziert: R, quelleUrl: "https://www.belex.sites.be.ch/app/de/texts_of_law/169.81", hinweis: "Letztwillige Verfuegung (Testament): Gebuehr nach gebotenem Zeitaufwand, mindestens 500 Franken (Art. 9 Abs. 1, Fassung Stand 01.03.2022). Geschaeft ohne Geschaeftswert -> Art. 1a Abs. 2. Stundenansatz Notar CHF 250-400 (Art. 3a Abs. 1). Frueherer Hoechstbetrag 3000 entfaellt in", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 400. Letztwillige Verfuegung (Testament): Gebuehr nach gebotenem Zeitaufwand, mindestens 500 Franken (Art. 9 Abs. 1, Fassung Stand 01.03.2022). Geschaeft ohne Geschaeftswert -> Art. 1a" } },
    LU: { kanton: 'LU', erlassName: "Verordnung über die Beurkundungsgebühren (BeurkGebV)", erlassNr: "SRL 258", artikel: "BeurkGebV § 19 Abs. 1 (SRL 258)", stand: "2022-01-01", verifiziert: R, quelleUrl: "https://srl.lu.ch/api/de/versions/3870/pdf_file_with_annexes", hinweis: "§ 19 Abs. 1: 'Bei der Errichtung einer öffentlichen letztwilligen Verfügung (Art. 499 ZGB) ... beträgt die Gebühr Fr. 500.– bis Fr. 5000.–.' Abänderung Fr. 150–2000 (Abs. 2), Aufhebung Fr. 150–300 (Abs. 3). Fester Rahmen, keine Aufwand-Formel.", regel: { typ: 'rahmen', vonChf: 500, bisChf: 5000 } },
