    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 9 (ZGB 499)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Oeffentliche letztwillige Verfuegung: Grundgebuehr-Rahmen 500-1800 (nach Ermessen, Art. 3 Abs. 1) PLUS 1%o des Verfuegungswerts, hoechstens insgesamt 20000. Bei 1M: Grundgebuehr (500-1800) + 1000 (1%o) -> ca. 1500-2800. sockelChf=Untergrenze Grundgebuehr; Promille-Band ab 0.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: Infinity, sockelChf: 500, abChf: 0, prozent: 0.1, minChf: 500, maxChf: 20000 }] } },
