    BL: { kanton: 'BL', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "SGS 217.13", artikel: "NotGebV SGS 217.13 §9 Abs.1 lit. b (i.V.m. §9 Abs.2, §8)", stand: "1.11.2012", verifiziert: R, quelleUrl: "https://bl.clex.ch/app/de/texts_of_law/217.13", hinweis: "Rahmengebuehr fuer letztwillige Verfuegungen: 400-1'500 Fr. Kein freier Aufwand/keine Vereinbarung. Innerhalb des Rahmens Abrechnung nach Zeitaufwand zu den Stundenansaetzen §8 (Notar 180-260 Fr./Std). Obergrenze ausnahmsweise ueberschreitbar (§9 Abs.3).", regel: { typ: 'rahmen', vonChf: 400, bisChf: 1500 } },
    SH: { kanton: 'SH', erlassName: "Verordnung über die Gebühren für öffentliche Beurkundungen (Notariatsgebührenverordnung); ergänzend für grundbuchliche Beurkundungen die Grundbuchgebührenverordnung (SHR 211.433)", erlassNr: "221.101 (ergänzend 211.433)", artikel: "221.101 § 1 Abs. 1 Ziff. 5 i.V.m. § 3", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://rechtsbuch.sh.ch/api/de/texts_of_law/221.101", hinweis: "KORREKTUR: nicht 'Vereinbarung/Aufwand', sondern Auffangtatbestand 'Übrige Beurkundungsgebühren Fr. 100.-- bis Fr. 10'000.--' (Notariatsgebührenverordnung SHR 221.101 § 1 Abs. 1 Ziff. 5). § 3: Bemessung INNERHALB des Rahmens nach Arbeits-/Zeitaufwand, Bedeutung, Schwierigkeit und", regel: { typ: 'rahmen', vonChf: 100, bisChf: 10000 } },
