    AG: { kanton: 'AG', erlassName: "Dekret über den Notariatstarif", erlassNr: "SAR 295.250", artikel: "§ 1 Dekret über den Notariatstarif (SAR 295.250)", stand: "2025-01-01", verifiziert: R, quelleUrl: "https://gesetzessammlungen.ag.ch/api/de/texts_of_law/295.250", hinweis: "Letztwillige Verfügung: kein Promille-Tatbestand (§2 NT abschliessend für Grundstück-Eigentumsübertragung/Baurechte). Aufwandtarif §1: Stundenansatz höchstens CHF 300; bei fehlender Vereinbarung Festsetzung nach §§73/74 BeurG.", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 300. Letztwillige Verfügung: kein Promille-Tatbestand (§2 NT abschliessend für Grundstück-Eigentumsübertragung/Baurechte). Aufwandtarif §1: Stundenansatz höchstens CHF 300; bei fehlend" } },
