    NW: { kanton: 'NW', erlassName: "Beurkundungsgebührenverordnung", erlassNr: "NG 268.12", artikel: "NG 268.12 § 35 i.V.m. § 20", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://gesetze.nw.ch/app/de/texts_of_law/268.12", hinweis: "Verpfruendungsvertrag (Art. 522 OR): Gebuehr vom Vermoegenswert nach den Ansaetzen von § 20 (NICHT direkt § 20-Tatbestand, sondern Verweis). Bei 1 Mio. Vermoegenswert = 2'100.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 0, abChf: 0, prozent: 0.25, minChf: 300 }, { bisChf: 500000, sockelChf: 500, abChf: 200000, prozent: 0.2 }, { bisChf: 1000000, sockelChf: 1100, abChf: 500000, prozent: 0.15 }, { bisChf: 5000000, sockelChf: 1850, abChf: 1000000, prozent: 0.1 }, { bisChf: Infinity, sockelChf: 5850, abChf: 5000000, prozent: 0.05 }] } },
