    SG: { kanton: 'SG', erlassName: "Verordnung über die Gebühren für Amtshandlungen der Grundbuchämter und für die Durchführung von Grundstückschätzungen (GB-GebV) — für grundstücksbezogene Beurkundungen; ergänzt durch Gebührentarif für die Kantons- und Gemeindeverwaltung (GebT), Abschnitt III «Beurkundungen und Beglaubigungen», für die übrigen öffentlichen Beurkundungen", erlassNr: "914.5 (GB-GebV); 821.5 (GebT)", artikel: "GebT (sGS 821.5) Nr. 60.12", stand: "1.1.2026", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.sg.ch/api/de/versions/2935/pdf_file_with_annexes", hinweis: "Verpfruendungsvertrag (Art. 522 Abs. 1 OR): FESTER Rahmen 300-1500, kein Promille. Frueher faelschlich GB-GebV Nr. 20.01. Bei zusaetzlicher Grundstuecksuebertragung kommt separat Nr. 20.01 (degressiv) hinzu.", regel: { typ: 'rahmen', vonChf: 300, bisChf: 1500 } },
    GR: { kanton: 'GR', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "BR 210.370", artikel: "Art. 19 Abs. 1 lit. d NotGebV; Erbverpfruendung Art. 13 Abs. 1 lit. f (BR 210.370)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file", hinweis: "Verpfruendung steht NICHT in Art. 16 (Sachenrecht). Verpfruendungsvertrag = Art. 19 Abs. 1 lit. d: Sockel Fr. 500 + 1 Promille vom Vertragswert ueber 200'000, hoechstens Fr. 15'000. Bei 1M = 1'300 (NICHT 1'000). Erbverpfruendung = Art. 13 Abs. 1 lit. f, gleiche Struktur. maxChf 1", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 500, abChf: 0, prozent: 0, minChf: 500, maxChf: 15500 }, { bisChf: Infinity, sockelChf: 500, abChf: 200000, prozent: 0.1, maxChf: 15500 }] } },
