    NE: { kanton: 'NE', erlassName: "Arrêté tarif des émoluments des notaires", erlassNr: "RSN 166.31", artikel: "Tarif notaires RSN 166.31 Art. 7 i.V.m. Art. 14 ch. 54 (Wertgebuehrentabelle)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm", hinweis: "Verpfruendungsvertrag (contrat d'entretien viager): keine eigene Tarifziffer; als entgeltlicher Vermoegensuebertragungsvertrag nach Wert (Art. 7) -> Tabelle ch. 54. Bei reiner Renten-/Wohnrechtskomponente subsidiaer ch. 40 (150-500). Tiefe Konfidenz mangels ausdruecklicher Ziffer", regel: { typ: 'rahmen', vonChf: 800, bisChf: 10000 } },
    GE: { kanton: 'GE', erlassName: "Règlement sur les émoluments des notaires (REmNot)", erlassNr: "RSG E 6 05.03", artikel: "Art. 10 al. 1 REmNot (RSG E 6 05.03)", stand: "2015-04-30", verifiziert: R, quelleUrl: "https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm", hinweis: "Contrat d'entretien viager: Soweit eine Eigentumsuebertragung (z.B. Liegenschaft) enthalten ist, gilt die translative Staffel Art. 10 al. 1 auf den uebertragenen Wert. OHNE translative Wirkung gilt Art. 27 (acte non prevu, 100-2000 francs). Default hier: Art.-10-Staffel (haeufigs", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 0, abChf: 0, prozent: 0.7, minChf: 200 }, { bisChf: 400000, sockelChf: 1400, abChf: 200000, prozent: 0.6 }, { bisChf: 800000, sockelChf: 2600, abChf: 400000, prozent: 0.45 }, { bisChf: 1000000, sockelChf: 4400, abChf: 800000, prozent: 0.4 }, { bisChf: 1500000, sockelChf: 5200, abChf: 1000000, prozent: 0.35 }, { bisChf: 2000000, sockelChf: 6950, abChf: 1500000, prozent: 0.3 }, { bisChf: 3500000, sockelChf: 8450, abChf: 2000000, prozent: 0.25 }, { bisChf: 5000000, sockelChf: 12200, abChf: 3500000, prozent: 0.2 }, { bisChf: 7500000, sockelChf: 15200, abChf: 5000000, prozent: 0.15 }, { bisChf: 10000000, sockelChf: 18950, abChf: 7500000, prozent: 0.1 }, { bisChf: 20000000, sockelChf: 21450, abChf: 10000000, prozent: 0.075 }, { bisChf: Infinity, sockelChf: 28950, abChf: 20000000, prozent: 0.05 }] } },
    JU: { kanton: 'JU', erlassName: "Décret fixant les émoluments des notaires", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 12 al. 1 (i.V.m. al. 2)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Contrat d'entretien viager (Verpfruendung) ist in Art. 12 ausdruecklich erfasst; Bemessungswert nach al. 2 = valeur de tous les revenus du beneficiaire. Staffel 3/2/1 Promille, min 200, max 2'000. Korrigiert: bisher Art. 9 al. 1 / Aufwand.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 0, abChf: 0, prozent: 0.3, minChf: 200, maxChf: 2000 }, { bisChf: 500000, sockelChf: 300, abChf: 100000, prozent: 0.2, maxChf: 2000 }, { bisChf: Infinity, sockelChf: 1100, abChf: 500000, prozent: 0.1, maxChf: 2000 }] } },
