    UR: { kanton: 'UR', erlassName: "Notariatstarif der Urner Notarinnen und Notare (Verbands-Konventionaltarif)", erlassNr: "urilaw.ch (RB 9.2311)", artikel: "Notariatstarif UR Ziff. 5.1 Bst. g i.V.m. 5.2 (Grundgebuehr A)", stand: "17.3.2015", verifiziert: R, quelleUrl: "https://www.urilaw.ch/fileadmin/user_upload/documents/Notariatstarif-Uri.pdf", hinweis: "Errichtung einer Aktiengesellschaft ist in Tarif A genannt (Ziff. 5.1 lit. g). Flat-on-total (degressiv) auf GESAMTwert (= Kapital) der Stufe, NICHT marginal. bis 250k 3%o (Min 500), bis 1M 2,5%o (Min 750), ueber 1M 2%o (Min 2'500). Bei 1M = CHF 2'500. Cap Ziff. 8.3 >10'000; Max", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 250000, sockelChf: 0, abChf: 0, prozent: 0.3, minChf: 500, maxChf: 30000 }, { bisChf: 1000000, sockelChf: 750, abChf: 250000, prozent: 0.25, maxChf: 30000 }, { bisChf: Infinity, sockelChf: 2625, abChf: 1000000, prozent: 0.2, maxChf: 30000 }] } },
