    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 31 lit. a (OR 620 ff./764 ff.)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Gruendung AG/Kommanditaktiengesellschaft: degressive Wertstaffel 3%o bis 200k, 2%o bis 500k, 1%o ueber 500k, mind. 800, hoechstens 20000. Bei 1M = 1700 (nicht ein freier Rahmen 800-20000). Bei oeffentlich zu beurkundenden Sacheinlagen/Sachuebernahmen zusaetzlich Gebuehr nach Ziff", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 0, abChf: 0, prozent: 0.3, minChf: 800, maxChf: 20000 }, { bisChf: 500000, sockelChf: 600, abChf: 200000, prozent: 0.2, maxChf: 20000 }, { bisChf: Infinity, sockelChf: 1200, abChf: 500000, prozent: 0.1, maxChf: 20000 }] } },
