    GL: { kanton: 'GL', erlassName: "Verordnung über Beurkundung und Beglaubigung mit Gebührentarif", erlassNr: "GS III B/3/2", artikel: "Art. A1-3 (Anhang) GS III B/3/2", stand: "1.1.2009", verifiziert: R, quelleUrl: "https://gesetze.gl.ch/app/de/texts_of_law/III%20B%2F3%2F2", hinweis: "OR-Gruendung ohne eigene Gebuehrenposition (A1-2 regelt nur Buergschaft); Auffangrahmen A1-3: 100-1000 Fr. nach Bedeutung/Aufwand.", regel: { typ: 'rahmen', vonChf: 100, bisChf: 1000 } },
