    SO: { kanton: 'SO', erlassName: "Gebührentarif (GT)", erlassNr: "BGS 615.11", artikel: "§ 26 Abs. 1 lit. c GT (BGS 615.11)", stand: "2026-06-16", verifiziert: R, quelleUrl: "https://bgs.so.ch/app/de/texts_of_law/615.11", hinweis: "Beurkundung nach Gesellschaftsrecht (AG/GmbH/Gesellschaften). Ermessensrahmen nach § 3 Abs. 1 GT.", regel: { typ: 'rahmen', vonChf: 500, bisChf: 10000 } },
    BS: { kanton: 'BS', erlassName: "Verordnung über den Notariatstarif", erlassNr: "SG 292.400", artikel: "§ 11 Ziff. 33 lit. a Notariatstarif SG 292.400", stand: "1.7.2016", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400", hinweis: "KORREKTUR: DEGRESSIVE Marginalstaffel. Kapital unter CHF 100000: Rahmen CHF 750 bis CHF 2000; bei CHF 100000 fix CHF 2000 (Sockel); vom Mehrbetrag >100000 0,24%, >200000 0,22%, >1 Mio 0,2%, >3 Mio 0,15%, >5 Mio 0,1%, >10 Mio 0,075%; hoechstens CHF 50000. sockelChf=2000 ist die Gr", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 2000, abChf: 100000, prozent: 0.24, minChf: 750, maxChf: 50000 }, { bisChf: 1000000, sockelChf: 2240, abChf: 200000, prozent: 0.22000000000000003, maxChf: 50000 }, { bisChf: 3000000, sockelChf: 4000, abChf: 1000000, prozent: 0.2, maxChf: 50000 }, { bisChf: 5000000, sockelChf: 8000, abChf: 3000000, prozent: 0.15, maxChf: 50000 }, { bisChf: 10000000, sockelChf: 11000, abChf: 5000000, prozent: 0.1, maxChf: 50000 }, { bisChf: Infinity, sockelChf: 16000, abChf: 10000000, prozent: 0.075, maxChf: 50000 }] } },
    BL: { kanton: 'BL', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "SGS 217.13", artikel: "NotGebV SGS 217.13 §9 Abs.1 lit. c (i.V.m. §9 Abs.2, §8)", stand: "1.11.2012", verifiziert: R, quelleUrl: "https://bl.clex.ch/app/de/texts_of_law/217.13", hinweis: "Rahmengebuehr fuer Gruendung von AG und GmbH ohne qualifizierte Tatbestaende: 700-2'000 Fr. (lit. c, AG und GmbH gemeinsam). Innerhalb des Rahmens Abrechnung nach Zeitaufwand §8 (Notar 180-260 Fr./Std). Hinweis Amtsnotariat: GebV SGS 211.71 §14 Ziff.7 lit. a Gruendung AG = fix 1'", regel: { typ: 'rahmen', vonChf: 700, bisChf: 2000 } },
    SH: { kanton: 'SH', erlassName: "Verordnung über die Gebühren für öffentliche Beurkundungen (Notariatsgebührenverordnung); ergänzend für grundbuchliche Beurkundungen die Grundbuchgebührenverordnung (SHR 211.433)", erlassNr: "221.101 (ergänzend 211.433)", artikel: "221.101 § 1 Abs. 1 Ziff. 2 Bst. a", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://rechtsbuch.sh.ch/api/de/texts_of_law/221.101", hinweis: "KORREKTUR: kein reiner Rahmen, sondern 2‰ des Grund-/Stammkapitals, mindestens Fr. 800.--, höchstens Fr. 10'000.-- (221.101 § 1 Abs. 1 Ziff. 2 Bst. a). Min greift unter Fr. 400'000 Kapital, Max ab Fr. 5'000'000.", regel: { typ: 'promille', promille: 2, minChf: 800, maxChf: 10000 } },
    AR: { kanton: 'AR', erlassName: "Gesetz über die Gebühren der Gemeinden (Gebührentarif für die Gemeinden)", erlassNr: "bGS 153.2", artikel: "Art. 12 Ziff. 5.8 lit. a bGS 153.2", stand: "1.1.2018", verifiziert: R, quelleUrl: "https://ar.clex.ch/api/de/versions/1203/pdf_file", hinweis: "Errichtung von Grund-/Stammkapital: Fr. 300 bis zu einem Kapital von Fr. 200'000, danach Fr. 50 je weitere Fr. 100'000 Kapital. Degressiver Festbetrag (kein flacher Promillesatz). Baender bilden den festen Sockel (300 fuer erste 200k) plus Stufenzuschlag Fr. 50 je 100k ab.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 300, abChf: 0, prozent: 0, minChf: 300 }, { bisChf: Infinity, sockelChf: 300, abChf: 200000, prozent: 0 }] } },
    AI: { kanton: 'AI', erlassName: "Gebührentarif (GebT)", erlassNr: "GS 172.513", artikel: "Art. 14 Abs. 3 Ziff. 1 GebT (GS 172.513)", stand: "2026-01-01", verifiziert: R, quelleUrl: "https://ai.clex.ch/app/de/texts_of_law/172.513", hinweis: "Gruendung (handelsregisterrechtliche Beurkundung) 400-4'000.", regel: { typ: 'rahmen', vonChf: 400, bisChf: 4000 } },
    SG: { kanton: 'SG', erlassName: "Verordnung über die Gebühren für Amtshandlungen der Grundbuchämter und für die Durchführung von Grundstückschätzungen (GB-GebV) — für grundstücksbezogene Beurkundungen; ergänzt durch Gebührentarif für die Kantons- und Gemeindeverwaltung (GebT), Abschnitt III «Beurkundungen und Beglaubigungen», für die übrigen öffentlichen Beurkundungen", erlassNr: "914.5 (GB-GebV); 821.5 (GebT)", artikel: "GebT (sGS 821.5) Nr. 60.13 (i.V.m. Nrn. 60.13-18)", stand: "1.1.2026", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.sg.ch/api/de/versions/2935/pdf_file_with_annexes", hinweis: "DEGRESSIVE STAFFEL, kein Rahmen: 385 fuer die ersten 100000 (Sockel), 80 je weitere VOLLE 100000 (= 0,8 Promille je 100k-Tranche, nur ganze Tranchen), hoechstens 15000. Bsp Kapital 1 Mio. = 385 + 9x80 = 1105. Sockel 385 als sockelChf; erste Tranche promille 0 (im Sockel enthalten", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 385, abChf: 0, prozent: 0, maxChf: 15000 }, { bisChf: Infinity, sockelChf: 385, abChf: 100000, prozent: 0.08, maxChf: 15000 }] } },
    GR: { kanton: 'GR', erlassName: "Verordnung über die Notariatsgebühren (NotGebV)", erlassNr: "BR 210.370", artikel: "Art. 17 Abs. 1 lit. a NotGebV (BR 210.370)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.gr-lex.gr.ch/api/de/versions/3348/pdf_file", hinweis: "Errichtung AG (auch Kommanditaktiengesellschaft): Sockel Fr. 1'000 + 1 Promille vom Aktienkapital ueber 200'000; KEIN Maximum genannt. Bei 1M = 1'000 + 800 = 1'800 (NICHT 1'000). Sacheinlage = wie Art. 15/16 lit. a. Beleg: gr-lex.gr.ch/app/de/texts_of_law/210.370", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 1000, abChf: 0, prozent: 0, minChf: 1000 }, { bisChf: Infinity, sockelChf: 1000, abChf: 200000, prozent: 0.1 }] } },
    AG: { kanton: 'AG', erlassName: "Dekret über den Notariatstarif", erlassNr: "SAR 295.250", artikel: "§ 1 Dekret über den Notariatstarif (SAR 295.250)", stand: "2025-01-01", verifiziert: R, quelleUrl: "https://gesetzessammlungen.ag.ch/api/de/texts_of_law/295.250", hinweis: "AG-Gründung: kein Promille-Tatbestand (§2 NT nur Grundstück/Baurecht). Aufwandtarif §1, Stundenansatz höchstens CHF 300; bei fehlender Vereinbarung Festsetzung nach §§73/74 BeurG nach Bedeutung und Schwierigkeit (kein vom Aktienkapital abhängiger Wertgebührentarif).", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 300. AG-Gründung: kein Promille-Tatbestand (§2 NT nur Grundstück/Baurecht). Aufwandtarif §1, Stundenansatz höchstens CHF 300; bei fehlender Vereinbarung Festsetzung nach §§73/74 BeurG" } },
