    TI: { kanton: 'TI', erlassName: "Legge sulla tariffa notarile", erlassNr: "RL 952.300", artikel: "Art. 5 cpv. 1 i.V.m. Art. 3 lit. l Legge sulla tariffa notarile (RL 952.300)", stand: "2013-11-26", verifiziert: R, quelleUrl: "https://m3.ti.ch/CAN/RLeggi/public/index.php/raccolta-leggi/pdfatto/atto/148", hinweis: "AG-Gruendung = wertbestimmbar nach Art. 3 lit. l: Wert = Kapitalbetrag bei Gruendung (bzw. hoeherer Wert der Sacheinlagen) -> volle Art.-5-Staffel, min. CHF 500. Beispiel Kapital 1M = CHF 3'875. Statutenerstellung/Sacheinlagevertraege sind nach Art. 1 cpv. 4 separat nach Stundent", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 250000, sockelChf: 0, abChf: 0, prozent: 0.5, minChf: 500 }, { bisChf: 500000, sockelChf: 1250, abChf: 250000, prozent: 0.4 }, { bisChf: 750000, sockelChf: 2250, abChf: 500000, prozent: 0.35 }, { bisChf: 1000000, sockelChf: 3125, abChf: 750000, prozent: 0.3 }, { bisChf: 2000000, sockelChf: 3875, abChf: 1000000, prozent: 0.25 }, { bisChf: 5000000, sockelChf: 6375, abChf: 2000000, prozent: 0.2 }, { bisChf: 10000000, sockelChf: 12375, abChf: 5000000, prozent: 0.1 }, { bisChf: 50000000, sockelChf: 17375, abChf: 10000000, prozent: 0.05 }, { bisChf: Infinity, sockelChf: 37375, abChf: 50000000, prozent: 0 }] } },
