    VS: { kanton: 'VS', erlassName: "Tarif des émoluments des notaires", erlassNr: "RS 178.104", artikel: "Art. 13 al. 1 i.V.m. Art. 11 let. e ch. 1 (acte constitutif SA, art. 629 CO); Bemessung Art. 12 al. 1, RS 178.104", stand: "01.01.2011", verifiziert: R, quelleUrl: "https://lex.vs.ch/app/fr/texts_of_law/178.104", hinweis: "Acte constitutif de la SA ist proportionaler Akt (Art. 11 let. e ch. 1) -> degressive Staffel Art. 13 al. 1. Bemessungsgrundlage = Kapital (Art. 12 al. 1). KORREKTUR: nicht 'nach Vereinbarung/Aufwand'.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 200, abChf: 5000, prozent: 0.5, minChf: 200 }, { bisChf: 500000, sockelChf: 1175, abChf: 200000, prozent: 0.4 }, { bisChf: 1000000, sockelChf: 2375, abChf: 500000, prozent: 0.3 }, { bisChf: 10000000, sockelChf: 3875, abChf: 1000000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 21875, abChf: 10000000, prozent: 0.1 }] } },
    NE: { kanton: 'NE', erlassName: "Arrêté fixant le tarif des émoluments des notaires", erlassNr: "RSN 166.31", artikel: "Tarif notaires RSN 166.31 Art. 14 ch. 81 lit. A ch. 1 (Constitution SA)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm", hinweis: "AG-Gruendung: Grundgebuehr (proces-verbal) 500 fr. PLUS degressive marginale Promille auf das Aktienkapital (5 Promille bis 100k, 2 bis 500k, 1 bis 1M, 0,5 darueber), Hoechstgebuehr 11800 fr.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 500, abChf: 0, prozent: 0.5, maxChf: 11800 }, { bisChf: 500000, sockelChf: 1000, abChf: 100000, prozent: 0.2, maxChf: 11800 }, { bisChf: 1000000, sockelChf: 1800, abChf: 500000, prozent: 0.1, maxChf: 11800 }, { bisChf: Infinity, sockelChf: 2300, abChf: 1000000, prozent: 0.05, maxChf: 11800 }] } },
    GE: { kanton: 'GE', erlassName: "Règlement sur les émoluments des notaires (REmNot)", erlassNr: "RSG E 6 05.03", artikel: "Art. 25 al. 1 et al. 2 REmNot (RSG E 6 05.03)", stand: "2015-04-30", verifiziert: R, quelleUrl: "https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm", hinweis: "Acte constitutif: Grundgebuehr-Rahmen 500-2000 francs (Art. 25 al. 1) PLUS proportionale Kapitalstaffel auf das Gruendungskapital (Art. 25 al. 2). sockelChf 500 = Untergrenze des Grundgebuehr-Rahmens; Rahmen 500-2000 nach Ermessen. Bei Sacheinlage Immobilien zusaetzlich Verkaufse", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 50000, sockelChf: 500, abChf: 0, prozent: 0.7 }, { bisChf: 100000, sockelChf: 850, abChf: 50000, prozent: 0.6 }, { bisChf: 200000, sockelChf: 1150, abChf: 100000, prozent: 0.5 }, { bisChf: 300000, sockelChf: 1650, abChf: 200000, prozent: 0.4 }, { bisChf: 400000, sockelChf: 2050, abChf: 300000, prozent: 0.3 }, { bisChf: 500000, sockelChf: 2350, abChf: 400000, prozent: 0.2 }, { bisChf: 10000000, sockelChf: 2550, abChf: 500000, prozent: 0.1 }, { bisChf: Infinity, sockelChf: 12050, abChf: 10000000, prozent: 0.05 }] } },
    JU: { kanton: 'JU', erlassName: "Décret concernant les émoluments des notaires du 6 décembre 1978", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 16 al. 1", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Art. 16 al. 1: Sockel CHF 300 fuer die ersten 100'000 Gesellschaftskapital (erstes Band promille=0 entspricht Pauschale 300, abgebildet via sockelChf), dann 2 Promille fuer die naechsten 400'000 (100'001-500'000), 1,5 Promille ueber 500'000. CHF 300 ist nur der Sockel; bei hoeher", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 300, abChf: 0, prozent: 0, minChf: 300 }, { bisChf: 500000, sockelChf: 300, abChf: 100000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 1100, abChf: 500000, prozent: 0.15 }] } },
