    BS: { kanton: 'BS', erlassName: "Verordnung über den Notariatstarif", erlassNr: "SG 292.400", artikel: "§ 11 Ziff. 33 (Ueberschrift) lit. a Notariatstarif SG 292.400", stand: "1.7.2016", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400", hinweis: "KORREKTUR: GmbH faellt unter dieselbe Ziff. 33 (Ueberschrift 'Aktiengesellschaft, Kommandit-Aktiengesellschaft und GmbH') lit. a wie die AG. Identische DEGRESSIVE Marginalstaffel: Kapital unter 100000 Rahmen 750-2000; ab 100000 Grundtaxe 2000 plus Mehrbetragsstaffel; hoechstens 5", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 2000, abChf: 100000, prozent: 0.24, minChf: 750, maxChf: 50000 }, { bisChf: 1000000, sockelChf: 2240, abChf: 200000, prozent: 0.22000000000000003, maxChf: 50000 }, { bisChf: 3000000, sockelChf: 4000, abChf: 1000000, prozent: 0.2, maxChf: 50000 }, { bisChf: 5000000, sockelChf: 8000, abChf: 3000000, prozent: 0.15, maxChf: 50000 }, { bisChf: 10000000, sockelChf: 11000, abChf: 5000000, prozent: 0.1, maxChf: 50000 }, { bisChf: Infinity, sockelChf: 16000, abChf: 10000000, prozent: 0.075, maxChf: 50000 }] } },
