    VS: { kanton: 'VS', erlassName: "Tarif des émoluments des notaires", erlassNr: "RS 178.104", artikel: "Art. 13 al. 1 i.V.m. Art. 11 let. e ch. 4 (acte constitutif Sarl, art. 777 CO); Bemessung Art. 12 al. 1, RS 178.104", stand: "01.01.2011", verifiziert: R, quelleUrl: "https://lex.vs.ch/app/fr/texts_of_law/178.104", hinweis: "Acte constitutif de la Sarl ist proportionaler Akt (Art. 11 let. e ch. 4) -> degressive Staffel Art. 13 al. 1 auf das Stammkapital (Art. 12 al. 1). KORREKTUR: nicht 'nach Vereinbarung/Aufwand'.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 200, abChf: 5000, prozent: 0.5, minChf: 200 }, { bisChf: 500000, sockelChf: 1175, abChf: 200000, prozent: 0.4 }, { bisChf: 1000000, sockelChf: 2375, abChf: 500000, prozent: 0.3 }, { bisChf: 10000000, sockelChf: 3875, abChf: 1000000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 21875, abChf: 10000000, prozent: 0.1 }] } },
