    GE: { kanton: 'GE', erlassName: "Règlement sur les émoluments des notaires (REmNot)", erlassNr: "RSG E 6 05.03", artikel: "Art. 25 al. 1 et al. 2 REmNot (RSG E 6 05.03)", stand: "2015-04-30", verifiziert: R, quelleUrl: "https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm", hinweis: "Wie ag_gruendung: Grundgebuehr-Rahmen 500-2000 (Art. 25 al. 1) PLUS Kapitalstaffel (Art. 25 al. 2). Bei Einpersonengesellschaft (societe unipersonnelle) ist die maximale Grundgebuehr 1000 statt 2000 (Art. 25 al. 1 Satz 2). sockelChf 500. Korrigiert von 'flach 500'.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 50000, sockelChf: 500, abChf: 0, prozent: 0.7 }, { bisChf: 100000, sockelChf: 850, abChf: 50000, prozent: 0.6 }, { bisChf: 200000, sockelChf: 1150, abChf: 100000, prozent: 0.5 }, { bisChf: 300000, sockelChf: 1650, abChf: 200000, prozent: 0.4 }, { bisChf: 400000, sockelChf: 2050, abChf: 300000, prozent: 0.3 }, { bisChf: 500000, sockelChf: 2350, abChf: 400000, prozent: 0.2 }, { bisChf: 10000000, sockelChf: 2550, abChf: 500000, prozent: 0.1 }, { bisChf: Infinity, sockelChf: 12050, abChf: 10000000, prozent: 0.05 }] } },
    JU: { kanton: 'JU', erlassName: "Décret concernant les émoluments des notaires du 6 décembre 1978", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 16 al. 1", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Sarl: gleiche Staffel wie SA nach Art. 16 al. 1 (Sockel 300 bis 100'000 Kapital, 2 Promille 100'001-500'000, 1,5 Promille darueber). Korrigiert: bisher fixer Wert 300.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 300, abChf: 0, prozent: 0, minChf: 300 }, { bisChf: 500000, sockelChf: 300, abChf: 100000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 1100, abChf: 500000, prozent: 0.15 }] } },
