    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 2 (ZGB 81)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Errichtung/Aenderung/Aufhebung Stiftung: Grundgebuehr-Rahmen 500-1800 PLUS 1%o des gestifteten Vermoegens, hoechstens insgesamt 20000. Bei 1M: Grundgebuehr (500-1800) + 1000 -> ca. 1500-2800. Bei gleichzeitiger Grundstueckuebertragung zusaetzlich halbe Gebuehr nach Ziff. 12.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: Infinity, sockelChf: 500, abChf: 0, prozent: 0.1, minChf: 500, maxChf: 20000 }] } },
