    FR: { kanton: 'FR', erlassName: "Tarif des émoluments des notaires", erlassNr: "RSF 261.16", artikel: "Art. 4 ch. 5 (i.V.m. Art. 3)", stand: "7.10.1986", verifiziert: R, quelleUrl: "https://bdlf.fr.ch/api/fr/versions/8428/pdf_file", hinweis: "KORRIGIERT: Constitution de fondation (Stiftung) = Art. 4 ch. 5 = degressive Marginalstaffel: bis 50'000 = 500 (Sockel), 4‰/3‰/1‰/0,5‰, max 12'000. Massgebende Summe = Stiftungsvermögen nach Art. 3.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 50000, sockelChf: 500, abChf: 0, prozent: 0, minChf: 500, maxChf: 12000 }, { bisChf: 100000, sockelChf: 500, abChf: 50000, prozent: 0.4, maxChf: 12000 }, { bisChf: 500000, sockelChf: 700, abChf: 100000, prozent: 0.3, maxChf: 12000 }, { bisChf: 1000000, sockelChf: 1900, abChf: 500000, prozent: 0.1, maxChf: 12000 }, { bisChf: Infinity, sockelChf: 2400, abChf: 1000000, prozent: 0.05, maxChf: 12000 }] } },
