    SH: { kanton: 'SH', erlassName: "Verordnung über die Gebühren für öffentliche Beurkundungen (Notariatsgebührenverordnung); ergänzend für grundbuchliche Beurkundungen die Grundbuchgebührenverordnung (SHR 211.433)", erlassNr: "221.101 (ergänzend 211.433)", artikel: "221.101 § 1 Abs. 1 Ziff. 1", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://rechtsbuch.sh.ch/api/de/texts_of_law/221.101", hinweis: "KORREKTUR: 2‰ des Stiftungsvermögens, mindestens Fr. 500.--, höchstens Fr. 10'000.-- (221.101 § 1 Abs. 1 Ziff. 1). Bisher als reiner Rahmen 500-10'000 kodiert; tatsächlich 2‰ dazwischen (Min greift unter Fr. 250'000, Max ab Fr. 5'000'000).", regel: { typ: 'promille', promille: 2, minChf: 500, maxChf: 10000 } },
