    AI: { kanton: 'AI', erlassName: "Gebührentarif (GebT)", erlassNr: "GS 172.513", artikel: "Art. 14 Abs. 3 Ziff. 7 GebT (GS 172.513)", stand: "2026-01-01", verifiziert: R, quelleUrl: "https://ai.clex.ch/app/de/texts_of_law/172.513", hinweis: "Errichtung einer Stiftung (Art. 81 ZGB) 400-4'000.", regel: { typ: 'rahmen', vonChf: 400, bisChf: 4000 } },
    SG: { kanton: 'SG', erlassName: "Verordnung über die Gebühren für Amtshandlungen der Grundbuchämter und für die Durchführung von Grundstückschätzungen (GB-GebV) — für grundstücksbezogene Beurkundungen; ergänzt durch Gebührentarif für die Kantons- und Gemeindeverwaltung (GebT), Abschnitt III «Beurkundungen und Beglaubigungen», für die übrigen öffentlichen Beurkundungen", erlassNr: "914.5 (GB-GebV); 821.5 (GebT)", artikel: "GebT (sGS 821.5) Nr. 60.01 (Ansaetze wie Nr. 60.13)", stand: "1.1.2026", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.sg.ch/api/de/versions/2935/pdf_file_with_annexes", hinweis: "Errichtung Stiftung (Art. 81 ZGB): Ansaetze je nach Stiftungskapital WIE Nr. 60.13 (Staffel 385 + 80 je weitere volle 100000), jedoch eigener Gesamtrahmen 330-3850 (statt 15000). Sockel 385, gekappt im Rahmen 330-3850. Geaendert durch XXVI. Nachtrag.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 385, abChf: 0, prozent: 0, minChf: 330, maxChf: 3850 }, { bisChf: Infinity, sockelChf: 385, abChf: 100000, prozent: 0.08, maxChf: 3850 }] } },
