    TG: { kanton: 'TG', erlassName: "Gesetz über die Gebühren und Gemengsteuern der Grundbuchämter und Notariate (GGG)", erlassNr: "RB 632.1", artikel: "§ 16 GGG (RB 632.1)", stand: "2026 (konsolidiert)", verifiziert: R, quelleUrl: "https://www.rechtsbuch.tg.ch/api/de/texts_of_law/632.1", hinweis: "KORREKTUR (Drittprüfung): § 16 Rahmen Fr. 200–10'000 pro Geschäft nach Aufwand/Bedeutung; nicht frei vereinbar.", regel: { typ: 'rahmen', vonChf: 200, bisChf: 10000 } },
    TI: { kanton: 'TI', erlassName: "Legge sulla tariffa notarile (del 26 novembre 2013)", erlassNr: "RL 952.300", artikel: "Art. 9 lit. i Legge sulla tariffa notarile (RL 952.300)", stand: "2013-11-26", verifiziert: R, quelleUrl: "https://m3.ti.ch/CAN/RLeggi/public/index.php/raccolta-leggi/pdfatto/atto/148", hinweis: "Stiftungserrichtung (costituzione di fondazione) = wertunbestimmbarer Akt -> Fix CHF 3'000 (Art. 9 lit. i, zusammen mit Verein/Gesellschaft mit unbestimmtem Kapital). Hinweis: Eine Stiftung mit bestimmbarem Widmungsvermoegen koennte argumentativ unter Art. 5 fallen; der Tarif ord", regel: { typ: 'fix', chf: 3000 } },
