    VS: { kanton: 'VS', erlassName: "Tarif des émoluments des notaires", erlassNr: "RS 178.104", artikel: "Art. 13 al. 1 i.V.m. Art. 11 let. a (constitution d'une fondation, art. 81 al. 1/87 al. 1/89bis al. 1 CC); Statuten separat Art. 16 let. a, RS 178.104", stand: "01.01.2011", verifiziert: R, quelleUrl: "https://lex.vs.ch/app/fr/texts_of_law/178.104", hinweis: "Errichtungsakt der Stiftung ist proportionaler Akt (Art. 11 let. a) -> degressive Staffel Art. 13 al. 1, Bemessung = Stiftungsvermoegen. Die Redaktion der Statuten/Reglemente ist separat FIX 200-1'000 CHF (Art. 16 let. a). KORREKTUR: Errichtungsakt nicht 'nach Vereinbarung/Aufwan", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 200000, sockelChf: 200, abChf: 5000, prozent: 0.5, minChf: 200 }, { bisChf: 500000, sockelChf: 1175, abChf: 200000, prozent: 0.4 }, { bisChf: 1000000, sockelChf: 2375, abChf: 500000, prozent: 0.3 }, { bisChf: 10000000, sockelChf: 3875, abChf: 1000000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 21875, abChf: 10000000, prozent: 0.1 }] } },
    NE: { kanton: 'NE', erlassName: "Arrêté fixant le tarif des émoluments des notaires", erlassNr: "RSN 166.31", artikel: "Tarif notaires RSN 166.31 Art. 14 ch. 9 (Acte constitutif ou modificatif d'une fondation)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm", hinweis: "Errichtung/Aenderung Stiftung 150-2000 fr.", regel: { typ: 'rahmen', vonChf: 150, bisChf: 2000 } },
