    JU: { kanton: 'JU', erlassName: "Décret concernant les émoluments des notaires du 6 décembre 1978", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 16 al. 1", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Creation d'une fondation: Art. 16 al. 1, Staffel nach Stiftungskapital (Sockel 300 bis 100'000, 2 Promille 100'001-500'000, 1,5 Promille darueber). CHF 300 nur Sockel. Korrigiert: bisher fixer Wert 300.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 100000, sockelChf: 300, abChf: 0, prozent: 0, minChf: 300 }, { bisChf: 500000, sockelChf: 300, abChf: 100000, prozent: 0.2 }, { bisChf: Infinity, sockelChf: 1100, abChf: 500000, prozent: 0.15 }] } },
