    ZH: { kanton: 'ZH', erlassName: "Notariatsgebührenverordnung (NotGebV)", erlassNr: "LS 243", artikel: "NotGebV LS 243, Anhang Ziff. 4.4.1 (Buergschaft, pro Beurkundungsakt)", stand: "01.01.2024", verifiziert: R, quelleUrl: "https://www.zh.ch/de/politik-staat/gesetze-beschluesse/gesetzessammlung/zhlex-ls/erlass-243-2009_03_09-2009_07_01-123.html", hinweis: "KORREKTUR: 0,5‰ vom verbuergten Hoechstbetrag im Rahmen von 100-500 (nicht Fix 500). minChf=100 / maxChf=500 als Klammer um den Promillesatz. MwSt nach § 2 zusaetzlich.", regel: { typ: 'promille', promille: 0.5, minChf: 100, maxChf: 500 } },
    BE: { kanton: 'BE', erlassName: "Verordnung über die Notariatsgebühren (GebVN)", erlassNr: "BSG 169.81", artikel: "Art. 19 Abs. 1 i.V.m. Art. 1a Abs. 2, Art. 3a Abs. 1 GebVN (BSG 169.81)", stand: "01.03.2022", verifiziert: R, quelleUrl: "https://www.belex.sites.be.ch/app/de/texts_of_law/169.81", hinweis: "Buergschaft oder Buergschaftsversprechen: Gebuehr nach gebotenem Zeitaufwand, mindestens 100 Franken (Art. 19 Abs. 1, Fassung Stand 01.03.2022). Geschaeft ohne tarifierten Geschaeftswert -> Art. 1a Abs. 2. Stundenansatz Notar CHF 250-400 (Art. 3a Abs. 1). Frueherer Rahmen 300-500", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand, Stundenansatz CHF 400. Buergschaft oder Buergschaftsversprechen: Gebuehr nach gebotenem Zeitaufwand, mindestens 100 Franken (Art. 19 Abs. 1, Fassung Stand 01.03.2022). Geschaeft ohne tarifierten Geschae" } },
    LU: { kanton: 'LU', erlassName: "Verordnung über die Beurkundungsgebühren (BeurkGebV)", erlassNr: "SRL 258", artikel: "BeurkGebV § 35 Abs. 1 (SRL 258)", stand: "2022-01-01", verifiziert: R, quelleUrl: "https://srl.lu.ch/api/de/versions/3870/pdf_file_with_annexes", hinweis: "§ 35 Abs. 1: 'Bei der Errichtung einer Bürgschaft (Art. 493 Abs. 1 OR), bei der Erhöhung der Haftungssumme sowie bei der Umwandlung einer einfachen in eine Solidarbürgschaft beträgt die Gebühr 2 ‰ des Haftungsbetrages, mindestens Fr. 300.–, höchstens Fr. 1000.–.' Flacher 2‰-Satz;", regel: { typ: 'promille', promille: 2, minChf: 300, maxChf: 1000 } },
    UR: { kanton: 'UR', erlassName: "Notariatstarif der Urner Notarinnen und Notare (Verbands-Konventionaltarif)", erlassNr: "urilaw.ch (RB 9.2311)", artikel: "Notariatstarif UR Ziff. 5.1 Bst. f i.V.m. 5.2 (Grundgebuehr A)", stand: "17.3.2015", verifiziert: R, quelleUrl: "https://www.urilaw.ch/fileadmin/user_upload/documents/Notariatstarif-Uri.pdf", hinweis: "Buergschaftsverpflichtung ist in Tarif A ausdruecklich genannt (Ziff. 5.1 lit. f). Flat-on-total (degressiv) auf GESAMTwert (= Buergschaftssumme), NICHT marginal. Saetze/Min wie Ziff. 5.2. Bei 1M = CHF 2'500. Cap Ziff. 8.3 >10'000; Max Ziff. 8.4 CHF 30'000.", regel: { typ: 'staffel_sockel_prozent', baender: [{ bisChf: 250000, sockelChf: 0, abChf: 0, prozent: 0.3, minChf: 500, maxChf: 30000 }, { bisChf: 1000000, sockelChf: 750, abChf: 250000, prozent: 0.25, maxChf: 30000 }, { bisChf: Infinity, sockelChf: 2625, abChf: 1000000, prozent: 0.2, maxChf: 30000 }] } },
    SZ: { kanton: 'SZ', erlassName: "Gebührentarif für Notare und Grundbuchverwalter sowie freiberufliche Urkundspersonen", erlassNr: "SRSZ 213.512", artikel: "§ 5 Abs. 1 Nr. 10", stand: "1.2.2021", verifiziert: R, quelleUrl: "https://www.sz.ch/public/upload/assets/7361/213_512.pdf", hinweis: "Bürgschaft pro Beurkundungsakt vom verbürgten Höchstbetrag 0.50‰, im Rahmen von Fr. 50 (Minimum) bis Fr. 1'000 (Maximum). Aufwand >2h zusätzlich Nr. 13.", regel: { typ: 'promille', promille: 0.5, minChf: 50, maxChf: 1000 } },
    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 29 (OR 493)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Buergschaftserklaerung: 1%o der Buergschaftssumme, mindestens 250, hoechstens 1000. Flacher Promillesatz (kein degressives Band). Bei 1M = 1000 (Hoechstgebuehr erreicht).", regel: { typ: 'promille', promille: 1, minChf: 250, maxChf: 1000 } },
