    OW: { kanton: 'OW', erlassName: "Verordnung über die Beurkundungsgebühren", erlassNr: "GDB 210.32", artikel: "Art. 10 Ziff. 40 (Andere Urkunden)", stand: "2012-04-01", verifiziert: R, quelleUrl: "https://gdb.ow.ch/app/de/texts_of_law/210.32", hinweis: "Reine Schuldanerkennung ist im Tarif nicht eigens aufgefuehrt und faellt unter Ziff. 40 (Urkunden ueber Tatbestaende, die in diesem Tarif nicht aufgezaehlt sind): Rahmen 200-1800, wertunabhaengig. Ziff. 12 (Eigentumsuebertragung) ist nicht einschlaegig. Konfidenz mittel, da Zuord", regel: { typ: 'rahmen', vonChf: 200, bisChf: 1800 } },
    NW: { kanton: 'NW', erlassName: "Beurkundungsgebührenverordnung", erlassNr: "NG 268.12", artikel: "NG 268.12 § 47 (beurkundungsbeduerftig) bzw. § 48 (nicht beurkundungsbeduerftig)", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://gesetze.nw.ch/app/de/texts_of_law/268.12", hinweis: "Keine spezielle Norm fuer Schuldanerkennung; KEINESFALLS § 20. Bei beurkundungsbeduerftigen Geschaeften ohne eigenen Tarif: § 47 Rahmen Fr. 200-2'000 (hier kodiert). Bei von den Parteien verlangter Beurkundung NICHT beurkundungsbeduerftiger Geschaefte: § 48 Wertstaffel 3/2.5/1.5/", regel: { typ: 'rahmen', vonChf: 200, bisChf: 2000 } },
