    BS: { kanton: 'BS', erlassName: "Verordnung über den Notariatstarif", erlassNr: "SG 292.400", artikel: "§ 11 Ziff. 42 (Auffangtatbestand); ggf. Ziff. 36a (Unterwerfungserklaerung), Ziff. 28 (grundpfandgesichert) Notariatstarif SG 292.400", stand: "1.7.2016", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.bs.ch/app/de/texts_of_law/292.400", hinweis: "Reine Schuldanerkennung beduerfte keiner Beurkundung; falls dennoch verlangt, gilt Ziff. 42 'gemaess Zeitaufwand und Bedeutung, mindestens CHF 200'. Mit Unterwerfungserklaerung (vollstreckbare oeffentliche Urkunde Art. 347 ZPO) gilt Ziff. 36a: separat CHF 400-1000, im Rahmen eine", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand. Reine Schuldanerkennung beduerfte keiner Beurkundung; falls dennoch verlangt, gilt Ziff. 42 'gemaess Zeitaufwand und Bedeutung, mindestens CHF 200'. Mit Unterwerfungserklaerung (vollstreckbare oeffentli" } },
    SH: { kanton: 'SH', erlassName: "Verordnung über die Gebühren für öffentliche Beurkundungen (Notariatsgebührenverordnung); ergänzend für grundbuchliche Beurkundungen die Grundbuchgebührenverordnung (SHR 211.433)", erlassNr: "221.101 (ergänzend 211.433)", artikel: "221.101 § 1 Abs. 1 Ziff. 5 i.V.m. § 3 (Pfandkontext: 211.433 § 13 Abs. 1 Ziff. 3.1)", stand: "01.01.2016", verifiziert: R, quelleUrl: "https://rechtsbuch.sh.ch/api/de/texts_of_law/221.101", hinweis: "KORREKTUR: selbständige öffentliche Beurkundung = 'Übrige Beurkundungsgebühren Fr. 100.-- bis Fr. 10'000.--' (221.101 § 1 Abs. 1 Ziff. 5) i.V.m. § 3 — kein freies Honorar. Im Pfandkontext (Schuldanerkennung als Pfandvertrag) stattdessen Grundbuchgebührenverordnung 211.433 § 13 Ab", regel: { typ: 'rahmen', vonChf: 100, bisChf: 10000 } },
    AR: { kanton: 'AR', erlassName: "Gesetz über die Gebühren der Gemeinden (Gebührentarif für die Gemeinden)", erlassNr: "bGS 153.2", artikel: "Art. 12 Ziff. 5.10 bGS 153.2 (Auffanggebuehr)", stand: "1.1.2018", verifiziert: R, quelleUrl: "https://ar.clex.ch/api/de/versions/1203/pdf_file", hinweis: "Kein eigener Tatbestand; Auffanggebuehr 'Beurkundungen aller Art, fuer die keine besondere Gebuehr festgesetzt ist' Fr. 50–500.", regel: { typ: 'rahmen', vonChf: 50, bisChf: 500 } },
    AI: { kanton: 'AI', erlassName: "Gebührentarif (GebT)", erlassNr: "GS 172.513", artikel: "Art. 14 Abs. 4 Ziff. 4 GebT (GS 172.513)", stand: "2026-01-01", verifiziert: R, quelleUrl: "https://ai.clex.ch/app/de/texts_of_law/172.513", hinweis: "Kein eigener Tatbestand fuer Schuldanerkennung; faellt unter Beurkundung nicht erwaehnter Willensaeusserungen 20-200 (Auffangtatbestand). Sofern grundpfandgesichert, siehe Errichtung Grundpfandrecht Art. 14 Abs. 2 Ziff. 3.", regel: { typ: 'rahmen', vonChf: 20, bisChf: 200 } },
    SG: { kanton: 'SG', erlassName: "Verordnung über die Gebühren für Amtshandlungen der Grundbuchämter und für die Durchführung von Grundstückschätzungen (GB-GebV) — für grundstücksbezogene Beurkundungen; ergänzt durch Gebührentarif für die Kantons- und Gemeindeverwaltung (GebT), Abschnitt III «Beurkundungen und Beglaubigungen», für die übrigen öffentlichen Beurkundungen", erlassNr: "914.5 (GB-GebV); 821.5 (GebT)", artikel: "GB-GebV (sGS 914.5) Art. 10 Nr. 21.01 (grundpfandgesichert) i.V.m. Art. 5 Abs. 2", stand: "1.6.2020", verifiziert: R, quelleUrl: "https://www.gesetzessammlung.sg.ch/api/de/versions/2935/pdf_file_with_annexes", hinweis: "Grundpfandgesicherte Schuldanerkennung folgt Nr. 21.01: 1 Promille der Pfandsumme, Rahmen 100-2000 (bei 1 Mio. = 1000, nicht 2000); einfacher Satz Art. 5 Abs. 2, mit Eintrag verdoppelt. REINE (nicht grundpfandbezogene) Schuldanerkennung: NICHT Nr. 20.01, sondern Auffangtarif (z.B", regel: { typ: 'promille', promille: 1, minChf: 100, maxChf: 2000 } },
