    NE: { kanton: 'NE', erlassName: "Arrêté tarif des émoluments des notaires", erlassNr: "RSN 166.31", artikel: "Tarif notaires RSN 166.31 Art. 7 i.V.m. Art. 14 ch. 54 (Wertgebuehrentabelle)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsn.ne.ch/DATA/program/books/RSN2015/20154/htm/16631.htm", hinweis: "Schuldanerkennung (reconnaissance de dette): keine eigene Tarifziffer; als wertbezogener Akt nach Art. 7 ueber Tabelle ch. 54 (feste Betraege je Wertband). Bei einfacher beglaubigter Form ggf. ch. 1 (Beglaubigung 20 fr./Unterschrift). Tiefe Konfidenz mangels ausdruecklicher Ziffe", regel: { typ: 'rahmen', vonChf: 800, bisChf: 10000 } },
    GE: { kanton: 'GE', erlassName: "Règlement sur les émoluments des notaires (REmNot)", erlassNr: "RSG E 6 05.03", artikel: "Art. 27 REmNot (RSG E 6 05.03)", stand: "2015-04-30", verifiziert: R, quelleUrl: "https://silgeneve.ch/legis/program/books/rsg/htm/rsg_e6_05p03.htm", hinweis: "Reconnaissance de dette ist nicht translativ → Art. 10 war falsch. Keine spezifische REmNot-Norm; als 'acte authentique non prevu' nach Art. 27 (100-2000 francs). Hinweis: Enthaelt die Urkunde eine vollstreckbare Klausel (titre executoire), gilt zusaetzlich/alternativ Art. 26A (w", regel: { typ: 'rahmen', vonChf: 100, bisChf: 2000 } },
    JU: { kanton: 'JU', erlassName: "Décret fixant les émoluments des notaires", erlassNr: "RSJU 189.61", artikel: "RSJU 189.61 Art. 6 al. 1 (i.V.m. Art. 3)", stand: "16.6.2026", verifiziert: R, quelleUrl: "https://rsju.jura.ch/fr/viewdocument.html?idn=20029&id=37829&download=1", hinweis: "Reine Schuldanerkennung hat keine eigene Promille-Position; einschlaegig Art. 6 al. 1 (activite accessoire, nach Bedeutung/Verantwortung/Zeit) bzw. Art. 3 (analoge Position). Kein fester Stundensatz im Erlass. Korrigiert: Artikelzitat Art. 9 al. 1 war falsch.", regel: { typ: 'formel_extern', hinweis: "Nach Zeitaufwand. Reine Schuldanerkennung hat keine eigene Promille-Position; einschlaegig Art. 6 al. 1 (activite accessoire, nach Bedeutung/Verantwortung/Zeit) bzw. Art. 3 (analoge Position). Kein fester Stundensatz im" } },
