    AR: { kanton: 'AR', erlassName: "Gesetz über die Gebühren der Gemeinden (Gebührentarif für die Gemeinden)", erlassNr: "bGS 153.2", artikel: "Art. 12 Ziff. 6 (Beglaubigung) bzw. Ziff. 5.10 (Beurkundung) bGS 153.2", stand: "1.1.2018", verifiziert: R, quelleUrl: "https://ar.clex.ch/api/de/versions/1203/pdf_file", hinweis: "Unterschriftsbeglaubigung Vollmacht: Ziff. 6 'Beglaubigungen aller Art' Fr. 5–20. Vollstaendige Beurkundung einer Vollmacht: Auffanggebuehr Ziff. 5.10 Fr. 50–500. Spannweite 5–500. (Korrektur Beglaubigungs-Obergrenze: 20, nicht 500.)", regel: { typ: 'rahmen', vonChf: 5, bisChf: 500 } },
